var selectedEmployee=0;function DeleteSelectedItems(){var a=$(":checkbox[id!=checkAllRecords]:checked");if(a.length<1){alert("Please select more than 1 records");return false}confirm("Really delete these records?")&&$.ajax({type:"POST",url:rootUri+"TaxiLocations/_DeleteSelectedItems",dataType:"json",data:a,success:onSuccess,error:onError});return false}function onSuccess(a){if(a.success=="True"){var b=$("#TaxiLocations").data("tGrid");b.rebind();$(".close-green").click(function(){$("#message-green").fadeOut("slow")})}else alert("Please Check Queue Information!");return false}function onComplete(){}function SearchItems(){$.ajax({type:"POST",url:rootUri+"TaxiLocations/_GetTaxiList",data:{name:$("#stand_name").val(),gps:$("#GPS_Addr").val()},success:onSuccess,error:onError})}function onError(a){alert("Error! Status = "+a.status)}function isAlphanumeric(a){return!/[^a-zA-Z0-9]/.test(a)}function btn_add_click(){document.location.href=rootUri+"TaxiLocations/Add"}var b_show_map=0;function btn_google_click(){var a=$("#ViewGoogleMap").data("tWindow");$("#google_search").show();a.title("Taxi Stand Map");a.center().open();return false}function draw_points(b){for(var d=b.split("<#ROW#>"),b="",c=0;c<d.length;c++){var a=d[c].split("<#COL#>");b+="<img src='"+rootUri+"Content/Images/TaxiLocations/taxi-point.png' style='position:absolute;left:"+a[2]+"px; top:"+a[3]+"px' onmouseover='onOverPoint(\""+a[0]+'","'+a[1]+'","'+a[2]+'","'+a[3]+'","'+a[4]+"\")' onmouseout='onOutPoint()' />"}$("#google_map").html(b)}$(function(){draw_points(points_data)});function onOverPoint(b,a,d,e,c){$("#info_stand_name").val(b);$("#info_gps_address").val(a);$("#info_longitude").val(d);$("#info_latitude").val(e);$("#info_stand_type").val(c);$("#point-info-dlg").show()}function onOutPoint(){$("#point-info-dlg").hide()};